+// reloadStatusStore keeps the outcome available to the HTTP API and on disk.
+// Its persistence is deliberately best-effort: losing diagnostic information
+// must never prevent Prometheus from starting.
+type reloadStatusStore struct {
+	mu     sync.RWMutex
+	path   string
+	status api_v1.ReloadStatus
+}
+
+func newReloadStatusStore(dir string) *reloadStatusStore {
+	s := &reloadStatusStore{
+		path: filepath.Join(dir, reloadStatusFilename),
+		status: emptyReloadStatus(),
+	}
+
+	b, err := os.ReadFile(s.path)
+	if err != nil {
+		return s
+	}
+	var status api_v1.ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil || !validReloadStatus(status) {
+		return s
+	}
+	s.status = normalizeReloadStatus(status)
+	return s
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{
+		ErrorCategory:     "none",
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]float64{},
+	}
+}
+
+func validReloadStatus(s api_v1.ReloadStatus) bool {
+	switch s.ErrorCategory {
+	case "none", "load_error", "apply_error", "rollback_error":
+		return true
+	default:
+		return false
+	}
+}
+
+func normalizeReloadStatus(s api_v1.ReloadStatus) api_v1.ReloadStatus {
+	if s.AppliedReloaders == nil {
+		s.AppliedReloaders = []string{}
+	}
+	if s.ReloaderTimingsMS == nil {
+		s.ReloaderTimingsMS = map[string]float64{}
+	}
+	return s
+}
+
+func (s *reloadStatusStore) Get() api_v1.ReloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	return cloneReloadStatus(s.status)
+}
+
+func (s *reloadStatusStore) Set(status api_v1.ReloadStatus) {
+	status = normalizeReloadStatus(status)
+	s.mu.Lock()
+	s.status = cloneReloadStatus(status)
+	s.mu.Unlock()
+
+	b, err := json.Marshal(status)
+	if err != nil {
+		return
+	}
