 func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
@@
 }
+
+// transactionalReloadConfig applies reloaders one at a time. On an apply
+// failure it restores every component from the last fully applied config,
+// avoiding the mixed state produced by the legacy best-effort reloader loop.
+// recordOutcome is false for startup config loading, which establishes the
+// initial rollback baseline but is not itself a reload attempt.
+func transactionalReloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), lastKnownGood *config.Config, statusStore *reloadStatusStore, recordOutcome bool, rls ...reloader) (conf *config.Config, err error) {
+	start := time.Now()
+	logger.Info("Loading configuration file", "filename", filename)
+	outcome := emptyReloadStatus()
+	if recordOutcome {
+		outcome.LastReloadID = start.UTC().Format(time.RFC3339Nano)
+	}
+
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+		if recordOutcome {
+			statusStore.Set(outcome)
+		}
+	}()
+
+	conf, err = config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		outcome.LastReloadSuccessful = false
+		outcome.ErrorCategory = "load_error"
+		outcome.ErrorMessage = err.Error()
+		return nil, fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	for _, rl := range rls {
+		rstart := time.Now()
+		applyErr := rl.reloader(conf)
+		outcome.ReloaderTimingsMS[rl.name] = float64(time.Since(rstart)) / float64(time.Millisecond)
+		if applyErr == nil {
+			outcome.AppliedReloaders = append(outcome.AppliedReloaders, rl.name)
+			continue
+		}
+
+		logger.Error("Failed to apply configuration", "reloader", rl.name, "err", applyErr)
+		outcome.LastReloadSuccessful = false
+		outcome.ErrorCategory = "apply_error"
+		outcome.ErrorMessage = applyErr.Error()
+		outcome.FailedReloader = rl.name
+
+		if len(outcome.AppliedReloaders) > 0 && lastKnownGood != nil {
+			outcome.RollbackAttempted = true
+			for _, rollbackReloader := range rls {
+				if rollbackErr := rollbackReloader.reloader(lastKnownGood); rollbackErr != nil {
+					logger.Error("Failed to roll back configuration", "reloader", rollbackReloader.name, "err", rollbackErr)
+					outcome.ErrorCategory = "rollback_error"
+					outcome.ErrorMessage = fmt.Sprintf("applying %s failed: %v; rollback with %s failed: %v", rl.name, applyErr, rollbackReloader.name, rollbackErr)
+					return nil, fmt.Errorf("applying configuration with %s failed: %w (rollback with %s failed: %v)", rl.name, applyErr, rollbackReloader.name, rollbackErr)
+				}
+			}
+			outcome.RollbackSuccessful = true
+		}
+		return nil, fmt.Errorf("applying configuration with %s failed: %w", rl.name, applyErr)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	outcome.LastReloadSuccessful = true
+	outcome.ErrorCategory = "none"
+	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	return conf, nil
+}
